      "gap_id": "GAP-001",
      "description": "Bill of Rights is in scaffold status with all articles (I–VI) undefined, awaiting human authorship. The DIO has no defined scope of enterprise, prohibited activities, core identity, or human authority reservation. Without a valid BoR, the Arbiter cannot enforce a perimeter and the MSP cannot translate constraints into operational rules. This leaves the DIO operating in an effectively unbounded state, violating the foundational requirement that the BoR be human-authored and established before the DIO can safely constrain its actions.",
      "grounding": "BoR Articles I (Scope of Enterprise), II (Prohibited Activities), III (Core Identity), IV (Human Authority Reservation), V (Amendment Protocol), VI (Interpretation Rules); MSP Purpose section states it translates the human-authored BoR, but no human-authored BoR exists.",
      "criticality": "Critical",
      "urgency": "Immediate",
      "impact": "Catastrophic",
      "priority_score": "CRITICAL",
      "notes": "Governance state is empty; no amendments have been made. The system awaits human principal action to populate the BoR and enable the full compliance pipeline."
    }
  ]
}

{
  "gaps": [
    {
      "gap_id": "GAP-001",
      "description": "No operational SLA or rule governing heartbeat-based organ state transitions; all organs flapping en masse from ALIVE to DEGRADED and back at ~30-second intervals with no normative boundary.",
      "grounded_in": {
        "document": "MSP",
        "section": "Rules",
        "reason": "The MSP Rules section is empty (bootstrap seed contains no rules). Consequently, there is no machine-actionable constraint on heartbeat interval, maximum missed pongs, recovery time, or state transition rate, allowing the observed systemic instability to persist without governance."
      },
      "priority": {
        "criticality": "critical",
        "urgency": "high",
        "impact": "high",
        "score": 0.95,
        "rationale": "All 26+ organs simultaneously lose and regain availability every 30 seconds, disabling any action adjudication by Nomos during each DEGRADED window. Without SLAs, this pattern is unaccountable and silently degrades overall system reliability."
      }
    },
    {
      "gap_id": "GAP-002",
      "description": "No organ availability target or uptime requirement defined; current state flapping yields effective uptime far below any reasonable service objective.",
      "grounded_in": {
        "document": "MSP",
        "section": "Rules",
        "reason": "The MSP Rules section contains no availability thresholds (e.g., 99.9% alive). Without such a rule, Nomos cannot detect or escalate availability breaches."
      },
      "priority": {
        "criticality": "high",
        "urgency": "high",
        "impact": "high",
        "score": 0.90,
        "rationale": "The pattern shows persistent violations of basic availability expectations; the gap prevents proactive enforcement or alerting."
      }
    },
    {
      "gap_id": "GAP-003",
      "description": "No runtime target for state-transition stabilization or anti-flapping mechanism; observed transition frequency is excessive (multiple full cycles per minute).",
      "grounded_in": {
        "document": "MSP",
        "section": "Rules",
        "reason": "Without a maximum-allowed state-change frequency or hysteresis rule, the DIO cannot rate-limit or dampen the observed rapid ALIVE↔DEGRADED oscillations."
      },
      "priority": {
        "criticality": "high",
        "urgency": "medium",
        "impact": "medium",
        "score": 0.75,
        "rationale": "High churn consumes resources and creates noise, though the immediate functional impact is already covered by GAP-001."
      }
    },
    {
      "gap_id": "GAP-004",
      "description": "No cadence baseline for the heartbeat protocol itself; the uniform ~30-second intervals and simultaneous TO/REVIVE across all organs suggest a single misconfigured timer without an MSP-defined acceptable frequency.",
      "grounded_in": {
        "document": "MSP",
        "section": "Rules",
        "reason": "MSP Rules are empty, so there is no declared heartbeat interval (e.g., 1s, 5s) or tolerance. The observed pattern cannot be judged against an operational standard."
      },
      "priority": {
        "criticality": "medium",
        "urgency": "medium",
        "impact": "medium",
        "score": 0.65,
        "rationale": "The underlying cadence defect likely causes the flap, but closing GAP-001 (heartbeat SLA) would also indirectly address this."
      }
    },
    {
      "gap_id": "GAP-005",
      "description": "No organ-specific recovery time objectives (RTO) or degradation isolation rules; all organs recover simultaneously after a missed_pong, indicating no graduated recovery or dependency ordering.",
      "grounded_in": {
        "document": "MSP",
        "section": "Genome References",
        "reason": "Genome documents, which extend the MSP with organ-specific operating rules, are currently empty. Consequently, there are no per-organ constraints on recovery sequencing, time-to-recover, or isolation during degradation."
      },
      "priority": {
        "criticality": "medium",
        "urgency": "low",
        "impact": "medium",
        "score": 0.55,
        "rationale": "While important for robust operations, the current crisis is mass failure; organ-specific refinements become more relevant after the global heartbeat issue is governed."
      }
    },
    {
      "gap_id": "GAP-006",
      "description": "No operational definition of prohibited heartbeat failure scenarios; the BoR scaffold lacks Article II (Prohibited Activities), leaving no constitutional hook for rules that forbid systemic heartbeat loss.",
      "grounded_in": {
        "document": "Bill of Rights",
        "section": "Article II — Prohibited Activities",
        "reason": "Article II is undefined, so there is no high-level prohibition against actions that cause systemic unavailability. This absence limits the MSP's ability to later encode hard boundaries on heartbeat behaviour."
      },
      "priority": {
        "criticality": "medium",
        "urgency": "low",
        "impact": "medium",
        "score": 0.50,
        "rationale": "The constitutional gap is foundational but less immediately actionable; MSP rules derived from a clear BoR would be stronger, but the heartbeat gap can be temporarily closed by MSP rules alone."
      }
    }
  ]
}
